package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.exception.RegulException;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.service.ConstantService;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

@Slf4j
public class ConstantManagerImp implements ConstantManager {

    private final ConstantService constantService;
    private final Admin admin;

    public ConstantManagerImp(Admin admin, ConstantService constantService) {
        this.admin = admin;
        this.constantService = constantService;
    }

    @Override
    public Constant getActualConstant(Konstanten constant, RekenTijd rekenTijd) {
        return getActualConstant(constant.getCode(), rekenTijd.rekenDatum, rekenTijd.eindDatum, rekenTijd.isAchterstal, false);
    }

    @Override
    public Constant getActualConstant(Konstanten constant, RekenTijd rekenTijd, LocalDate selectieDatum) {
        return getActualConstant(constant.getCode(), rekenTijd.rekenDatum, selectieDatum, rekenTijd.isAchterstal, false);
    }

    @Override
    public Constant getActualConstant(Integer code, RekenTijd rekenTijd) {
        return getActualConstant(code, rekenTijd.rekenDatum, rekenTijd.eindDatum, rekenTijd.isAchterstal, false);
    }

    @Override
    public Constant getActualConstantSafe(Integer code, RekenTijd rekenTijd) {
        return getActualConstant(code, rekenTijd.rekenDatum, rekenTijd.eindDatum, rekenTijd.isAchterstal, true);
    }

    @Override
    public Constant getActualConstant(Integer code, LocalDate rekenDatum, LocalDate selectieDatum, Boolean isAchterstal, boolean safe) {
        LocalDate datum;
        if (isAchterstal) {
            datum = rekenDatum;
        } else {
            datum = selectieDatum;
        }
        Constant resultaat = getByCodeDatumSafe(code, datum);
        if (!safe) {
            checkConstanteGevonden(resultaat, code, datum);
        }
        return resultaat;
    }

    @Override
    public Constant getByCodeDatum(Integer code, LocalDate datum) {
        return getByCodeDatumWithCheck(code, datum);
    }

    @Override
    public Constant getByCodeDatumSafe(Integer code, LocalDate datum) {
        return constantService.getByCodeDatum(admin, code, datum);
    }

    public Constant getByCodeDatumWithCheck(Integer code, LocalDate datum) {
        Constant resultaat = getByCodeDatumSafe(code, datum);
        checkConstanteGevonden(resultaat, code, datum);
        return resultaat;
    }

    @Override
    public Constant getByCodeDatum(Integer code, LocalDate datum, boolean safe) {
        if (safe) {
            return getByCodeDatumSafe(code, datum);
        } else {
            return getByCodeDatumWithCheck(code, datum);
        }
    }

    @Override
    public Constant getByCodeDatum(Konstanten constant, LocalDate datum) {
        Constant resultaat = constantService.getByCodeDatum(admin, constant, datum);
        checkConstanteGevonden(resultaat, constant.getCode(), datum);
        return resultaat;
    }

    private static void checkConstanteGevonden(Constant constant, Integer code) {
        if (constant == null) {
            log.debug("Constante met code {} niet gevonden.", code);
            throw new RegulException(null, null, Regulkode.CONSTANTE_NIET_GEVONDEN, null, null);
        }
    }

    private static void checkConstanteGevonden(Constant constant, Integer code, LocalDate date) {
        if (constant == null) {
            log.debug("Constante met code {} en datum {} niet gevonden.", code, date);
            throw new RegulException(null, null, Regulkode.CONSTANTE_NIET_GEVONDEN, null, null);
        }
    }
}
